  ///  B-spline interpolation result.
  public var INTERPOLATION_RESULT: BSPInterpolationResult? { let o = _accessor.offset(VT.INTERPOLATION_RESULT); return o == 0 ? nil : BSPInterpolationResult(_accessor.bb, o: _accessor.indirect(o + _accessor.position)) }
  public static func startBSP(_ fbb: inout FlatBufferBuilder) -> UOffset { fbb.startTable(with: 2) }
  public static func add(INTERPOLATION_REQUEST: Offset, _ fbb: inout FlatBufferBuilder) { fbb.add(offset: INTERPOLATION_REQUEST, at: VT.INTERPOLATION_REQUEST) }
  public static func add(INTERPOLATION_RESULT: Offset, _ fbb: inout FlatBufferBuilder) { fbb.add(offset: INTERPOLATION_RESULT, at: VT.INTERPOLATION_RESULT) }
  public static func endBSP(_ fbb: inout FlatBufferBuilder, start: UOffset) -> Offset { let end = Offset(offset: fbb.endTable(at: start)); return end }
  public static func createBSP(
    _ fbb: inout FlatBufferBuilder,
    INTERPOLATION_REQUESTOffset INTERPOLATION_REQUEST: Offset = Offset(),
    INTERPOLATION_RESULTOffset INTERPOLATION_RESULT: Offset = Offset()
  ) -> Offset {
    let __start = BSP.startBSP(&fbb)
    BSP.add(INTERPOLATION_REQUEST: INTERPOLATION_REQUEST, &fbb)
    BSP.add(INTERPOLATION_RESULT: INTERPOLATION_RESULT, &fbb)
    return BSP.endBSP(&fbb, start: __start)
  }

  public static func verify<T>(_ verifier: inout Verifier, at position: Int, of type: T.Type) throws where T: Verifiable {
    var _v = try verifier.visitTable(at: position)
